// Simplified file allocation simulation
#include <stdio.h>
#define DISK_SIZE 20
#define INDEX_SIZE 5

int disk[DISK_SIZE];

// Contiguous allocation
void contiguous_allocate(int start, int length, int fileId) {
 for (int i = start; i < start + length; i++)
 disk[i] = fileId;
 printf("Contiguous: File %d at blocks %d-%d\n", 
 fileId, start, start + length - 1);
}

// Linked allocation
typedef struct { int data; int next; } LinkedBlock;
LinkedBlock linkedDisk[DISK_SIZE];

void linked_allocate(int blocks[], int n, int fileId) {
 printf("Linked: File %d at blocks ", fileId);
 for (int i = 0; i < n; i++) {
 linkedDisk[blocks[i]].data = fileId;
 linkedDisk[blocks[i]].next = (i < n-1) ? blocks[i+1] : -1;
 printf("%d", blocks[i]);
 if (i < n-1) printf(" -> ");
 }
 printf("\n");
}

// Indexed allocation
void indexed_allocate(int indexBlock, int dataBlocks[], int n, int fileId) {
 disk[indexBlock] = -fileId; // Negative = index block
 printf("Indexed: File %d, Index at %d, Data at: ", fileId, indexBlock);
 for (int i = 0; i < n; i++) {
 disk[dataBlocks[i]] = fileId;
 printf("%d ", dataBlocks[i]);
 }
 printf("\n");
}

int main() {
 // Contiguous
 contiguous_allocate(0, 4, 1);

 // Linked
 int linked[] = {5, 8, 12, 15};
 linked_allocate(linked, 4, 2);

 // Indexed
 int data[] = {7, 9, 11, 14};
 indexed_allocate(6, data, 4, 3);

 return 0;
}

class DiskSimulator:
 def __init__(self, size=20):
 self.size = size
 self.disk = [None] * size

 def contiguous_allocate(self, file_id, start, length):
 """Contiguous allocation"""
 for i in range(start, start + length):
 self.disk[i] = file_id
 print(f"Contiguous: File {file_id} at blocks {start}-{start+length-1}")
 return {'start': start, 'length': length}

 def linked_allocate(self, file_id, blocks):
 """Linked allocation"""
 chain = []
 for i, block in enumerate(blocks):
 next_block = blocks[i+1] if i < len(blocks)-1 else None
 self.disk[block] = {'data': file_id, 'next': next_block}
 chain.append(block)
 print(f"Linked: File {file_id} chain: {' -> '.join(map(str, chain))}")
 return {'start': blocks[0], 'end': blocks[-1]}

 def indexed_allocate(self, file_id, index_block, data_blocks):
 """Indexed allocation"""
 self.disk[index_block] = {'type': 'index', 'pointers': data_blocks}
 for block in data_blocks:
 self.disk[block] = file_id
 print(f"Indexed: File {file_id}, Index at {index_block}, Data at {data_blocks}")
 return {'index': index_block}

# Demo
disk = DiskSimulator()

print("=== Allocation Methods Demo ===")
print()

# Contiguous
disk.contiguous_allocate(file_id=1, start=0, length=4)

# Linked
disk.linked_allocate(file_id=2, blocks=[5, 8, 12, 15])

# Indexed
disk.indexed_allocate(file_id=3, index_block=6, data_blocks=[7, 9, 11, 14])

print("\nDisk state:")
for i, block in enumerate(disk.disk):
 if block is not None:
 print(f" Block {i}: {block}")

import java.util.*;

public class AllocationMethods {
 static int[] disk = new int[20];

 static void contiguousAllocate(int fileId, int start, int length) {
 for (int i = start; i < start + length; i++)
 disk[i] = fileId;
 System.out.printf("Contiguous: File %d at blocks %d-%d%n", 
 fileId, start, start + length - 1);
 }

 static void linkedAllocate(int fileId, int[] blocks) {
 System.out.printf("Linked: File %d chain: ", fileId);
 for (int i = 0; i < blocks.length; i++) {
 disk[blocks[i]] = fileId;
 System.out.print(blocks[i]);
 if (i < blocks.length - 1) System.out.print(" -> ");
 }
 System.out.println();
 }

 static void indexedAllocate(int fileId, int indexBlock, int[] dataBlocks) {
 disk[indexBlock] = -fileId; // Mark as index
 System.out.printf("Indexed: File %d, Index at %d, Data at: ", 
 fileId, indexBlock);
 for (int block : dataBlocks) {
 disk[block] = fileId;
 System.out.print(block + " ");
 }
 System.out.println();
 }

 public static void main(String[] args) {
 contiguousAllocate(1, 0, 4);
 linkedAllocate(2, new int[]{5, 8, 12, 15});
 indexedAllocate(3, 6, new int[]{7, 9, 11, 14});
 }
}
